// Filter to active competitors and create items for each page to scrape
const competitors = $input.all();
const competitor_name = $json.competitor_name || null;

const pages_per_competitor = ['pricing', 'features', 'product', 'integrations'];
const output = [];

for (const competitor of competitors) {
  // Check if active
  if (competitor.active !== true && competitor.active !== 'TRUE' && competitor.active !== 'true') {
    continue;
  }

  // Filter by name if provided
  if (competitor_name && competitor.name.toLowerCase() !== competitor_name.toLowerCase()) {
    continue;
  }

  const base_url = competitor.website_url;
  if (!base_url) continue;

  // Create items for each page type
  for (const page_type of pages_per_competitor) {
    const page_url = base_url.replace(/\/$/, '') + '/' + page_type;

    output.push({
      json: {
        competitor_id: competitor.competitor_id,
        competitor_name: competitor.name,
        base_url: base_url,
        page_type: page_type,
        page_url: page_url,
        website_url: base_url
      }
    });
  }
}

return output;

// Chunk the extracted text content
const response = $json;
const competitor_name = $input.first().json.competitor_name;
const page_type = $input.first().json.page_type;
const source_url = $input.first().json.page_url;

let text_content = '';

// Extract text from Claude response
if (response.content && Array.isArray(response.content) && response.content.length > 0) {
  text_content = response.content[0].text || '';
}

// Parse JSON if present
let extracted_data = {};
const json_match = text_content.match(/\{[\s\S]*\}/);
if (json_match) {
  try {
    extracted_data = JSON.parse(json_match[0]);
    text_content = JSON.stringify(extracted_data, null, 2);
  } catch (e) {
    // Keep original text if JSON parsing fails
  }
}

// Chunking parameters
const chunk_size = 2000; // chars (roughly 500 tokens)
const overlap_size = 400; // chars (roughly 100 tokens)

const chunks = [];
const scraped_date = new Date().toISOString();

for (let i = 0; i < text_content.length; i += chunk_size - overlap_size) {
  const chunk_text = text_content.substring(i, i + chunk_size);
  const chunk_index = Math.floor(i / (chunk_size - overlap_size));

  const chunk_id = `${competitor_name.toLowerCase().replace(/\s+/g, '-')}-${page_type}-${chunk_index}`;

  chunks.push({
    json: {
      id: chunk_id,
      text: chunk_text,
      competitor_name: competitor_name,
      page_type: page_type,
      source_url: source_url,
      scraped_date: scraped_date,
      chunk_index: chunk_index,
      metadata: {
        competitor_name: competitor_name,
        doc_type: page_type,
        source_url: source_url,
        scraped_date: scraped_date
      }
    }
  });
}

return chunks;
